import{_ as t,c as i,o as s,a1 as e}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"DM 配对与访问控制：保护你的 AI 助手 | Clawdbot 教程","description":"了解 Clawdbot 的 DM 配对保护机制，学习如何通过 CLI 批准陌生发送者的配对请求、列出待批准请求和管理允许列表。本教程完整介绍配对流程、CLI 命令使用、访问策略配置和安全最佳实践，包含常见错误排查和 doctor 命令。","frontmatter":{"title":"DM 配对与访问控制：保护你的 AI 助手 | Clawdbot 教程","sidebarTitle":"管理陌生人访问","subtitle":"DM 配对与访问控制：保护你的 AI 助手","description":"了解 Clawdbot 的 DM 配对保护机制，学习如何通过 CLI 批准陌生发送者的配对请求、列出待批准请求和管理允许列表。本教程完整介绍配对流程、CLI 命令使用、访问策略配置和安全最佳实践，包含常见错误排查和 doctor 命令。","tags":["入门","安全","配对","访问控制"],"prerequisite":["start-gateway-startup"],"order":50},"headers":[],"relativePath":"zh/moltbot/moltbot/start/pairing-approval/index.md","filePath":"zh/moltbot/moltbot/start/pairing-approval/index.md"}'),l={name:"zh/moltbot/moltbot/start/pairing-approval/index.md"};function o(n,a,r,d,p,c){return s(),i("div",null,[...a[0]||(a[0]=[e(`<h1 id="dm-配对与访问控制-保护你的-ai-助手" tabindex="-1">DM 配对与访问控制：保护你的 AI 助手 <a class="header-anchor" href="#dm-配对与访问控制-保护你的-ai-助手" aria-label="Permalink to &quot;DM 配对与访问控制：保护你的 AI 助手&quot;">​</a></h1><h2 id="学完你能做什么" tabindex="-1">学完你能做什么 <a class="header-anchor" href="#学完你能做什么" aria-label="Permalink to &quot;学完你能做什么&quot;">​</a></h2><p>完成本教程后，你将能够：</p><ul><li>✅ 理解默认的 DM 配对保护机制</li><li>✅ 批准陌生发送者的配对请求</li><li>✅ 列出和管理待批准的配对请求</li><li>✅ 配置不同的 DM 访问策略（pairing/allowlist/open）</li><li>✅ 运行 doctor 检查安全配置</li></ul><h2 id="你现在的困境" tabindex="-1">你现在的困境 <a class="header-anchor" href="#你现在的困境" aria-label="Permalink to &quot;你现在的困境&quot;">​</a></h2><p>你可能刚配置了 WhatsApp 或 Telegram 渠道，希望与 AI 助手对话，但遇到了以下问题：</p><ul><li>&quot;为什么陌生人给我发消息，Clawdbot 不回复？&quot;</li><li>&quot;收到一个配对代码，不知道是什么意思&quot;</li><li>&quot;想批准某个人的请求，但不知道用什么命令&quot;</li><li>&quot;如何确认当前有哪些人在等待批准？&quot;</li></ul><p>好消息是：<strong>Clawdbot 默认启用 DM 配对保护</strong>，这是为了确保只有你授权的发送者才能与 AI 助手对话。</p><h2 id="什么时候用这一招" tabindex="-1">什么时候用这一招 <a class="header-anchor" href="#什么时候用这一招" aria-label="Permalink to &quot;什么时候用这一招&quot;">​</a></h2><p>当你需要：</p><ul><li>🛡 <strong>保护隐私</strong>：确保只有信任的人能与 AI 助手对话</li><li>✅ <strong>批准陌生人</strong>：允许新的发送者访问你的 AI 助手</li><li>🔒 <strong>严格访问控制</strong>：限制特定用户的访问权限</li><li>📋 <strong>批量管理</strong>：查看和管理所有待批准的配对请求</li></ul><hr><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><h3 id="什么是-dm-配对" tabindex="-1">什么是 DM 配对？ <a class="header-anchor" href="#什么是-dm-配对" aria-label="Permalink to &quot;什么是 DM 配对？&quot;">​</a></h3><p>Clawdbot 连接到真实的消息平台（WhatsApp、Telegram、Slack 等），这些平台上的<strong>私聊（DM）默认被视为不受信任的输入</strong>。</p><p>为了保护你的 AI 助手，Clawdbot 提供了<strong>配对机制</strong>：</p><div class="info custom-block"><p class="custom-block-title">配对流程</p><ol><li>陌生发送者向你发送消息</li><li>Clawdbot 检测到该发送者未被授权</li><li>Clawdbot 返回一个<strong>配对代码</strong>（8 位字符）</li><li>发送者需要将配对代码提供给你</li><li>你通过 CLI 批准该代码</li><li>发送者 ID 被添加到允许列表</li><li>发送者可以正常与 AI 助手对话</li></ol></div><h3 id="默认-dm-策略" tabindex="-1">默认 DM 策略 <a class="header-anchor" href="#默认-dm-策略" aria-label="Permalink to &quot;默认 DM 策略&quot;">​</a></h3><p><strong>所有渠道默认使用 <code>dmPolicy=&quot;pairing&quot;</code></strong>，这意味着：</p><table tabindex="0"><thead><tr><th>策略</th><th>行为</th></tr></thead><tbody><tr><td><code>pairing</code></td><td>未知发送者收到配对代码，消息不处理（默认）</td></tr><tr><td><code>allowlist</code></td><td>只允许 <code>allowFrom</code> 列表中的发送者</td></tr><tr><td><code>open</code></td><td>允许所有发送者（需显式配置 <code>&quot;*&quot;</code>）</td></tr><tr><td><code>disabled</code></td><td>完全禁用 DM 功能</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">安全提醒</p><p>默认的 <code>pairing</code> 模式是最安全的选择。除非你有特殊需求，否则不要修改为 <code>open</code> 模式。</p></div><hr><h2 id="🎒-开始前的准备" tabindex="-1">🎒 开始前的准备 <a class="header-anchor" href="#🎒-开始前的准备" aria-label="Permalink to &quot;🎒 开始前的准备&quot;">​</a></h2><p>确保你已经：</p><ul><li>[x] 完成了 <a href="./../getting-started/">快速开始</a> 教程</li><li>[x] 完成了 <a href="./../gateway-startup/">启动 Gateway</a> 教程</li><li>[x] 配置了至少一个消息渠道（WhatsApp、Telegram、Slack 等）</li><li>[x] Gateway 正在运行</li></ul><hr><h2 id="跟我做" tabindex="-1">跟我做 <a class="header-anchor" href="#跟我做" aria-label="Permalink to &quot;跟我做&quot;">​</a></h2><h3 id="第-1-步-理解配对代码的来源" tabindex="-1">第 1 步：理解配对代码的来源 <a class="header-anchor" href="#第-1-步-理解配对代码的来源" aria-label="Permalink to &quot;第 1 步：理解配对代码的来源&quot;">​</a></h3><p>当一个陌生发送者向你的 Clawdbot 发送消息时，他们会收到类似以下的回复：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Clawdbot: access not configured.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Telegram ID: 123456789</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Pairing code: AB3D7X9K</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Ask the bot owner to approve with:</span></span>
<span class="line"><span>clawdbot pairing approve telegram &lt;code&gt;</span></span></code></pre></div><p><strong>配对代码的关键特性</strong>（来源：<code>src/pairing/pairing-store.ts</code>）：</p><ul><li><strong>8 位字符</strong>：便于输入和记忆</li><li><strong>大写字母和数字</strong>：避免混淆</li><li><strong>排除易混淆字符</strong>：不包含 0、O、1、I</li><li><strong>1 小时有效期</strong>：超过时间会自动失效</li><li><strong>最多保留 3 个待批准请求</strong>：超过后会自动清理最旧的请求</li></ul><h3 id="第-2-步-列出待批准的配对请求" tabindex="-1">第 2 步：列出待批准的配对请求 <a class="header-anchor" href="#第-2-步-列出待批准的配对请求" aria-label="Permalink to &quot;第 2 步：列出待批准的配对请求&quot;">​</a></h3><p>在终端中运行以下命令：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">clawdbot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pairing</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> telegram</span></span></code></pre></div><p><strong>你应该看到</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Pairing requests (1)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>┌──────────────────┬────────────────┬────────┬──────────────────────┐</span></span>
<span class="line"><span>│ Code            │ ID            │ Meta   │ Requested            │</span></span>
<span class="line"><span>├──────────────────┼────────────────┼────────┼──────────────────────┤</span></span>
<span class="line"><span>│ AB3D7X9K        │ 123456789      │        │ 2026-01-27T10:30:00Z │</span></span>
<span class="line"><span>└──────────────────┴────────────────┴────────┴──────────────────────┘</span></span></code></pre></div><p>如果没有待批准的请求，你会看到：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>No pending telegram pairing requests.</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">支持的渠道</p><p>配对功能支持以下渠道：</p><ul><li>telegram</li><li>whatsapp</li><li>slack</li><li>discord</li><li>signal</li><li>imessage</li><li>msteams</li><li>googlechat</li><li>bluebubbles</li></ul></div><h3 id="第-3-步-批准配对请求" tabindex="-1">第 3 步：批准配对请求 <a class="header-anchor" href="#第-3-步-批准配对请求" aria-label="Permalink to &quot;第 3 步：批准配对请求&quot;">​</a></h3><p>使用发送者提供的配对代码批准访问：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">clawdbot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pairing</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> approve</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> telegram</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> AB3D7X9K</span></span></code></pre></div><p><strong>你应该看到</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✅ Approved telegram sender 123456789</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">批准后的效果</p><p>批准后，发送者 ID（123456789）会被自动添加到该渠道的允许列表中，存储在： <code>~/.clawdbot/credentials/telegram-allowFrom.json</code></p></div><h3 id="第-4-步-通知发送者-可选" tabindex="-1">第 4 步：通知发送者（可选） <a class="header-anchor" href="#第-4-步-通知发送者-可选" aria-label="Permalink to &quot;第 4 步：通知发送者（可选）&quot;">​</a></h3><p>如果你想自动通知发送者，可以使用 <code>--notify</code> 标志：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">clawdbot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pairing</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> approve</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> telegram</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> AB3D7X9K</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --notify</span></span></code></pre></div><p>发送者会收到以下消息（来源：<code>src/channels/plugins/pairing-message.ts</code>）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✅ Clawdbot access approved. Send a message to start chatting.</span></span></code></pre></div><p><strong>注意</strong>：<code>--notify</code> 标志要求 Clawdbot Gateway 正在运行，并且该渠道处于活跃状态。</p><h3 id="第-5-步-验证发送者可以正常对话" tabindex="-1">第 5 步：验证发送者可以正常对话 <a class="header-anchor" href="#第-5-步-验证发送者可以正常对话" aria-label="Permalink to &quot;第 5 步：验证发送者可以正常对话&quot;">​</a></h3><p>让发送者再次发送一条消息，AI 助手应该会正常回复。</p><hr><h2 id="检查点-✅" tabindex="-1">检查点 ✅ <a class="header-anchor" href="#检查点-✅" aria-label="Permalink to &quot;检查点 ✅&quot;">​</a></h2><p>完成以下检查确认配置正确：</p><ul><li>[ ] 运行 <code>clawdbot pairing list &lt;channel&gt;</code> 能看到待批准的请求</li><li>[ ] 使用 <code>clawdbot pairing approve &lt;channel&gt; &lt;code&gt;</code> 能成功批准</li><li>[ ] 批准后的发送者能正常与 AI 助手对话</li><li>[ ] 配对代码会在 1 小时后自动过期（可以通过再次发送消息验证）</li></ul><hr><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><h3 id="错误-1-找不到配对代码" tabindex="-1">错误 1：找不到配对代码 <a class="header-anchor" href="#错误-1-找不到配对代码" aria-label="Permalink to &quot;错误 1：找不到配对代码&quot;">​</a></h3><p><strong>错误信息</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>No pending pairing request found for code: AB3D7X9K</span></span></code></pre></div><p><strong>可能原因</strong>：</p><ul><li>配对代码已经过期（超过 1 小时）</li><li>配对代码输入错误（检查大小写）</li><li>发送者没有实际发送消息（配对代码只有在收到消息时才会生成）</li></ul><p><strong>解决方法</strong>：</p><ul><li>让发送者再次发送一条消息，生成新的配对代码</li><li>确保配对代码正确复制（注意大小写）</li></ul><h3 id="错误-2-渠道不支持配对" tabindex="-1">错误 2：渠道不支持配对 <a class="header-anchor" href="#错误-2-渠道不支持配对" aria-label="Permalink to &quot;错误 2：渠道不支持配对&quot;">​</a></h3><p><strong>错误信息</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Channel xxx does not support pairing</span></span></code></pre></div><p><strong>可能原因</strong>：</p><ul><li>渠道名称拼写错误</li><li>该渠道不支持配对功能</li></ul><p><strong>解决方法</strong>：</p><ul><li>运行 <code>clawdbot pairing list</code> 查看支持的渠道列表</li><li>使用正确的渠道名称</li></ul><h3 id="错误-3-通知失败" tabindex="-1">错误 3：通知失败 <a class="header-anchor" href="#错误-3-通知失败" aria-label="Permalink to &quot;错误 3：通知失败&quot;">​</a></h3><p><strong>错误信息</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Failed to notify requester: &lt;error details&gt;</span></span></code></pre></div><p><strong>可能原因</strong>：</p><ul><li>Gateway 未运行</li><li>渠道连接断开</li><li>网络问题</li></ul><p><strong>解决方法</strong>：</p><ul><li>确认 Gateway 正在运行</li><li>检查渠道连接状态：<code>clawdbot channels status</code></li><li>不使用 <code>--notify</code> 标志，手动通知发送者</li></ul><hr><h2 id="本课小结" tabindex="-1">本课小结 <a class="header-anchor" href="#本课小结" aria-label="Permalink to &quot;本课小结&quot;">​</a></h2><p>本教程介绍了 Clawdbot 的 DM 配对保护机制：</p><ul><li><strong>默认安全</strong>：所有渠道默认使用 <code>pairing</code> 模式，保护你的 AI 助手</li><li><strong>配对流程</strong>：陌生发送者收到 8 位配对代码，你需要通过 CLI 批准</li><li><strong>管理命令</strong>： <ul><li><code>clawdbot pairing list &lt;channel&gt;</code>：列出待批准请求</li><li><code>clawdbot pairing approve &lt;channel&gt; &lt;code&gt;</code>：批准配对</li></ul></li><li><strong>存储位置</strong>：允许列表存储在 <code>~/.clawdbot/credentials/&lt;channel&gt;-allowFrom.json</code></li><li><strong>自动过期</strong>：配对请求 1 小时后自动失效</li></ul><p>记住：<strong>配对机制是 Clawdbot 的安全基石</strong>，确保只有你授权的人能与 AI 助手对话。</p><hr><h2 id="下一课预告" tabindex="-1">下一课预告 <a class="header-anchor" href="#下一课预告" aria-label="Permalink to &quot;下一课预告&quot;">​</a></h2><blockquote><p>下一课我们将学习 <strong><a href="./../../faq/troubleshooting/">故障排除：解决常见问题</a></strong>。</p><p>你会学到：</p><ul><li>快速诊断和系统状态检查</li><li>解决 Gateway 启动、渠道连接、认证错误等问题</li><li>工具调用失败和性能优化的排查方法</li></ul></blockquote><hr><h2 id="附录-源码参考" tabindex="-1">附录：源码参考 <a class="header-anchor" href="#附录-源码参考" aria-label="Permalink to &quot;附录：源码参考&quot;">​</a></h2><details><summary><strong>点击展开查看源码位置</strong></summary><blockquote><p>更新时间：2026-01-27</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>文件路径</th><th>行号</th></tr></thead><tbody><tr><td>配对代码生成（8 位，排除易混淆字符）</td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/pairing/pairing-store.ts#L173-L181" target="_blank" rel="noreferrer"><code>src/pairing/pairing-store.ts</code></a></td><td>173-181</td></tr><tr><td>配对请求存储与 TTL（1 小时）</td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/pairing/pairing-store.ts#L11-L14" target="_blank" rel="noreferrer"><code>src/pairing/pairing-store.ts</code></a></td><td>11-14</td></tr><tr><td>批准配对命令</td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/cli/pairing-cli.ts#L107-L143" target="_blank" rel="noreferrer"><code>src/cli/pairing-cli.ts</code></a></td><td>107-143</td></tr><tr><td>配对代码消息生成</td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/pairing/pairing-messages.ts#L4-L20" target="_blank" rel="noreferrer"><code>src/pairing/pairing-messages.ts</code></a></td><td>4-20</td></tr><tr><td>允许列表存储</td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/pairing/pairing-store.ts#L457-L461" target="_blank" rel="noreferrer"><code>src/pairing/pairing-store.ts</code></a></td><td>457-461</td></tr><tr><td>支持 <code>pairing</code> 的渠道列表</td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/channels/plugins/pairing.ts#L11-L16" target="_blank" rel="noreferrer"><code>src/channels/plugins/pairing.ts</code></a></td><td>11-16</td></tr><tr><td>默认 DM 策略（pairing）</td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/config/zod-schema.providers-core.ts#L93" target="_blank" rel="noreferrer"><code>src/config/zod-schema.providers-core.ts</code></a></td><td>93</td></tr></tbody></table><p><strong>关键常量</strong>：</p><ul><li><code>PAIRING_CODE_LENGTH = 8</code>：配对代码长度</li><li><code>PAIRING_CODE_ALPHABET = &quot;ABCDEFGHJKLMNPQRSTUVWXYZ23456789&quot;</code>：配对代码字符集（排除 0O1I）</li><li><code>PAIRING_PENDING_TTL_MS = 60 * 60 * 1000</code>：配对请求有效期（1 小时）</li><li><code>PAIRING_PENDING_MAX = 3</code>：最大待批准请求数</li></ul><p><strong>关键函数</strong>：</p><ul><li><code>approveChannelPairingCode()</code>：批准配对代码并添加到允许列表</li><li><code>listChannelPairingRequests()</code>：列出待批准的配对请求</li><li><code>upsertChannelPairingRequest()</code>：创建或更新配对请求</li><li><code>addChannelAllowFromStoreEntry()</code>：添加发送者到允许列表</li></ul></details>`,92)])])}const b=t(l,[["render",o]]);export{g as __pageData,b as default};
